class Solution {
public:
    vector<int> findAllPeople(int n, vector<vector<int>>& meetings, int firstPerson) {
        vector<vector<int>> graph(n);
        vector<bool> visited(n, false);
        visited[0] = true;
        visited[firstPerson] = true;
        for (const auto& meeting : meetings) {
            int x = meeting[0], y = meeting[1], time = meeting[2];
            graph[x].push_back(y);
            graph[y].push_back(x);
        }
        for (int time = 0; time <= 10'000; time++) {
            queue<int> q;
            for (int i = 0; i < n; i++) {
                if (visited[i]) {
                    q.push(i);
                }
            }
            while (!q.empty()) {
                int person = q.front();
                q.pop();
                for (int neighbor : graph[person]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true;
                        q.push(neighbor);
                    }
                }
            }
        }
        vector<int> result;
        for (int i = 0; i < n; i++) {
            if (visited[i]) {
                result.push_back(i);
            }
        }
        return result;
    }
};
